```java
import java.util.*;

public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;
        List<List<int[]>> teleport_map = new ArrayList<>(m);
        for (int i = 0; i < m; i++) {
            teleport_map.add(new ArrayList<>(n));
            for (int j = 0; j < n; j++) {
                List<int[]> list = new ArrayList<>();
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (grid[x][y] <= grid[i][j]) {
                            list.add(new int[]{x, y});
                        }
                    }
                }
                teleport_map.get(i).set(j, list);
            }
        }

        long[][][] dp = new long[m][n][k + 1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int t = 0; t <= k; t++) {
                    dp[i][j][t] = Long.MAX_VALUE;
                }
            }
        }
        dp[0][0][0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{0, 0, 0, 0});

        int[][] directions = {{0, 1}, {1, 0}};

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long cost = current[0];
            int i = current[1];
            int j = current[2];
            int t = current[3];

            if (i == m - 1 && j == n - 1) {
                return cost;
            }

            for (int[] dir : directions) {
                int ni = i + dir[0];
                int nj = j + dir[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long newCost = cost + grid[ni][nj];
                    if (newCost < dp[ni][nj][t]) {
                        dp[ni][nj][t] = newCost;
                        pq.offer(new long[]{newCost, ni, nj, t});
                    }
                }
            }

            List<int[]> teleports = teleport_map.get(i).get(j);
            for (int[] xy : teleports) {
                int x = xy[0];
                int y = xy[1];
                if (t + 1 <= k) {
                    if (cost < dp[x][y][t + 1]) {
                        dp[x][y][t + 1] = cost;
                        pq.offer(new long[]{cost, x, y, t + 1});
                    }
                }
            }
        }

        long minCost = Long.MAX_VALUE;
        for (int t = 0; t <= k; t++) {
            if (dp[m - 1][n - 1][t] < minCost) {
                minCost = dp[m - 1][n - 1][t];
            }
        }
        return minCost;
    }
}
