public static long solve(long[][] grid, long k) {
    int m = grid.length;
    int n = grid[0].length;
    // Precompute teleport_map
    List<List<int[]>> teleport_map = new ArrayList<>();
    for (int i = 0; i < m; i++) {
        teleport_map.add(new ArrayList<>());
        for (int j = 0; j < n; j++) {
            for (int x = 0; x < m; x++) {
                for (int y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j]) {
                        teleport_map.get(i).add(new int[]{x, y});
                    }
                }
            }
        }
    }

    // Initialize DP
    long[][][] dp = new long[m][n][k+1];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            for (int t = 0; t <= k; t++) {
                dp[i][j][t] = Long.MAX_VALUE;
            }
        }
    }
    dp[0][0][0] = 0;

    // Priority queue
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
    pq.offer(new long[]{0, 0, 0, 0});

    // Directions for regular moves
    int[][] directions = {{0, 1}, {1, 0}};

    while (!pq.isEmpty()) {
        long[] current = pq.poll();
        long cost = current[0];
        int i = current[1];
        int j = current[2];
        int t = current[3];

        // Check if destination
        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        // Regular moves
        for (int[] dir : directions) {
            int ni = i + dir[0];
            int nj = j + dir[1];
            if (0 <= ni && ni < m && 0 <= nj && nj < n) {
                long new_cost = cost + grid[ni][nj];
                if (new_cost < dp[ni][nj][t]) {
                    dp[ni][nj][t] = new_cost;
                    pq.offer(new long[]{new_cost, ni, nj, t});
                }
            }
        }

        // Teleportation
        for (int[] xy : teleport_map.get(i)) {
            int x = xy[0];
            int y = xy[1];
            if (t + 1 <= k) {
                if (cost < dp[x][y][t + 1]) {
                    dp[x][y][t + 1] = cost;
                    pq.offer(new long[]{cost, x, y, t + 1});
                }
            }
        }
    }

    // If not found, return the minimum of the destination cell's dp
    long result = Long.MAX_VALUE;
    for (int t = 0; t <= k; t++) {
        if (dp[m-1][n-1][t] < result) {
            result = dp[m-1][n-1][t];
        }
    }
    return result;
}

