            long[] current = pq.poll();
            long cost = current[0];
            int i = current[1];
            int j = current[2];
            int t = current[3];

            if (i == m - 1 && j == n - 1) {
                return cost;
            }

            for (int[] dir : directions) {
                int ni = i + dir[0];
                int nj = j + dir[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long newCost = cost + grid[ni][nj];
                    if (newCost < dp[ni][nj][t]) {
